INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חדר מדרגות', '**חלון חדר מדרגות שבור או לא נפתח** — חלון בחדר מדרגות שבור, סדוק, או מנגנון פתיחה תקוע. חלון חדר המדרגות חיוני לאוורור ולפינוי עשן.. המלצה: החלפת זגוגית שבורה, תיקון מנגנון פתיחה, שימון צירים, או החלפת חלון שלם. עלות משוערת: ₪400-₪1500 (ליחידה)', '**חלון חדר מדרגות שבור או לא נפתח** — חלון בחדר מדרגות שבור, סדוק, או מנגנון פתיחה תקוע. חלון חדר המדרגות חיוני לאוורור ולפינוי עשן.. המלצה: החלפת זגוגית שבורה, תיקון מנגנון פתיחה, שימון צירים, או החלפת חלון שלם. עלות משוערת: ₪400-₪1500 (ליחידה)', 'חדר מדרגות מוגן חייב לכלול פתח אוורור עליון (טרישנטל) או חלונות הניתנים לפתיחה לפינוי עשן', 'חדר מדרגות מוגן חייב לכלול פתח אוורור עליון (טרישנטל) או חלונות הניתנים לפתיחה לפינוי עשן', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חדר מדרגות', '**חדר מדרגות ללא אוורור עליון (טרישנטל)** — חדר מדרגות מוגן ללא פתח אוורור עליון (טרישנטל) או שהפתח חסום. פתח עליון חיוני לפינוי עשן במקרה שריפה.. המלצה: פתיחת פתח אוורור עליון בגג חדר המדרגות או הסרת חסימה קיימת, התקנת רשת נגד מזיקים. עלות משוערת: ₪2000-₪6000 (ליחידה)', '**חדר מדרגות ללא אוורור עליון (טרישנטל)** — חדר מדרגות מוגן ללא פתח אוורור עליון (טרישנטל) או שהפתח חסום. פתח עליון חיוני לפינוי עשן במקרה שריפה.. המלצה: פתיחת פתח אוורור עליון בגג חדר המדרגות או הסרת חסימה קיימת, התקנת רשת נגד מזיקים. עלות משוערת: ₪2000-₪6000 (ליחידה)', 'חדר מדרגות מוגן חייב לכלול פתח אוורור עליון בשטח של לפחות 1 מ"ר לפינוי עשן טבעי', 'חדר מדרגות מוגן חייב לכלול פתח אוורור עליון בשטח של לפחות 1 מ"ר לפינוי עשן טבעי', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חדר מדרגות', '**סימון קומות חסר בחדר מדרגות** — מספרי קומות לא מסומנים בחדר מדרגות, או שהסימון דהוי ולא קריא. חיוני לפינוי ולזיהוי מיקום בשעת חירום.. המלצה: התקנת שילוט קומות פוספורסנטי (זוהר בחושך) בכל קומה בחדר המדרגות. עלות משוערת: ₪50-₪150 (ליחידה)', '**סימון קומות חסר בחדר מדרגות** — מספרי קומות לא מסומנים בחדר מדרגות, או שהסימון דהוי ולא קריא. חיוני לפינוי ולזיהוי מיקום בשעת חירום.. המלצה: התקנת שילוט קומות פוספורסנטי (זוהר בחושך) בכל קומה בחדר המדרגות. עלות משוערת: ₪50-₪150 (ליחידה)', 'כל קומה בחדר מדרגות חייבת להיות מסומנת במספר קומה בולט, קריא גם בתנאי עשן', 'כל קומה בחדר מדרגות חייבת להיות מסומנת במספר קומה בולט, קריא גם בתנאי עשן', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חדר מדרגות', '**מעקה מרפסת משותפת/גג רופף או נמוך** — מעקה בטיחות בגג הבניין או במרפסת משותפת רופף, חלוד, או בגובה נמוך מ-105 ס"מ. סכנת נפילה חמורה.. המלצה: חיזוק או החלפת מעקה, הגבהה לגובה תקני, טיפול בחלודה וצביעה מחדש. עלות משוערת: ₪400-₪1200 (למ"א)', '**מעקה מרפסת משותפת/גג רופף או נמוך** — מעקה בטיחות בגג הבניין או במרפסת משותפת רופף, חלוד, או בגובה נמוך מ-105 ס"מ. סכנת נפילה חמורה.. המלצה: חיזוק או החלפת מעקה, הגבהה לגובה תקני, טיפול בחלודה וצביעה מחדש. עלות משוערת: ₪400-₪1200 (למ"א)', 'ת"י 1142 — מעקה בטיחות בגג או במרפסת חייב להיות בגובה 105 ס"מ לפחות, יציב ועמיד', 'ת"י 1142 — מעקה בטיחות בגג או במרפסת חייב להיות בגובה 105 ס"מ לפחות, יציב ועמיד', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'חדר מדרגות', '**מדרגות — גובה שלח לא אחיד** — הפרשי גובה בין שלחי מדרגות — גורם למעידות.. המלצה: יישור שלחים, תיקון ריצוף מדרגות. עלות משוערת: ₪200-₪800 (ליחידה)', '**מדרגות — גובה שלח לא אחיד** — הפרשי גובה בין שלחי מדרגות — גורם למעידות.. המלצה: יישור שלחים, תיקון ריצוף מדרגות. עלות משוערת: ₪200-₪800 (ליחידה)', 'ת"י 1142 — הפרש גובה מותר בין שלחים: עד 5 מ"מ', 'ת"י 1142 — הפרש גובה מותר בין שלחים: עד 5 מ"מ', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'לובי ורכוש משותף', '**ריצוף שבור או מפולס לא אחיד בלובי** — אריחי ריצוף בלובי הכניסה שבורים, סדוקים, חסרים, או עם הפרשי גובה בין אריחים. מהווה סכנת מעידה ופוגם במראה הבניין.. המלצה: החלפת אריחים שבורים, יישור הפרשי גובה, מילוי רובה חסרה. עלות משוערת: ₪120-₪350 (למ"ר)', '**ריצוף שבור או מפולס לא אחיד בלובי** — אריחי ריצוף בלובי הכניסה שבורים, סדוקים, חסרים, או עם הפרשי גובה בין אריחים. מהווה סכנת מעידה ופוגם במראה הבניין.. המלצה: החלפת אריחים שבורים, יישור הפרשי גובה, מילוי רובה חסרה. עלות משוערת: ₪120-₪350 (למ"ר)', 'ריצוף בשטחים ציבוריים חייב להיות שלם, אחיד, ללא הפרשי גובה מעל 2 מ"מ, ועם מקדם חיכוך מספק', 'ריצוף בשטחים ציבוריים חייב להיות שלם, אחיד, ללא הפרשי גובה מעל 2 מ"מ, ועם מקדם חיכוך מספק', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'לובי ורכוש משותף', '**חדירת מים ורטיבות בלובי או בחדר מדרגות** — סימני רטיבות, עובש, או חדירת מים בקירות או בתקרת הלובי וחדר המדרגות. רטיבות בשטחים ציבוריים מעידה על כשל באיטום.. המלצה: איתור מקור הרטיבות, תיקון איטום גג/קירות חיצוניים, טיפול בעובש, וצביעה מחדש. עלות משוערת: ₪1500-₪5000 (ליחידה)', '**חדירת מים ורטיבות בלובי או בחדר מדרגות** — סימני רטיבות, עובש, או חדירת מים בקירות או בתקרת הלובי וחדר המדרגות. רטיבות בשטחים ציבוריים מעידה על כשל באיטום.. המלצה: איתור מקור הרטיבות, תיקון איטום גג/קירות חיצוניים, טיפול בעובש, וצביעה מחדש. עלות משוערת: ₪1500-₪5000 (ליחידה)', 'שטחים ציבוריים חייבים להיות יבשים וללא חדירת מים מהגג, מקירות חיצוניים, או מתשתיות אינסטלציה', 'שטחים ציבוריים חייבים להיות יבשים וללא חדירת מים מהגג, מקירות חיצוניים, או מתשתיות אינסטלציה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'לובי ורכוש משותף', '**תיבות דואר פגומות או חסרות** — תיבות דואר בלובי שבורות, ללא דלת, ללא מנעול, חלודות, או חסרות. תיבות דואר הן חלק מהרכוש המשותף.. המלצה: החלפת תיבות דואר פגומות, התקנת מנעולים, או החלפת מערכת תיבות דואר שלמה. עלות משוערת: ₪200-₪500 (ליחידה)', '**תיבות דואר פגומות או חסרות** — תיבות דואר בלובי שבורות, ללא דלת, ללא מנעול, חלודות, או חסרות. תיבות דואר הן חלק מהרכוש המשותף.. המלצה: החלפת תיבות דואר פגומות, התקנת מנעולים, או החלפת מערכת תיבות דואר שלמה. עלות משוערת: ₪200-₪500 (ליחידה)', 'כל דירה זכאית לתיבת דואר תקינה עם מנעול בלובי הכניסה', 'כל דירה זכאית לתיבת דואר תקינה עם מנעול בלובי הכניסה', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'לובי ורכוש משותף', '**דלת כניסה ראשית לבניין לא נסגרת או ללא מנגנון נעילה** — דלת כניסה ראשית לבניין לא נסגרת אוטומטית, מנגנון נעילה אלקטרוני (אינטרקום) לא פועל, או ציר שבור.. המלצה: תיקון או החלפת סוגר דלת, תיקון מנגנון נעילה אלקטרומגנטי, וכיוון צירים. עלות משוערת: ₪500-₪2000 (ליחידה)', '**דלת כניסה ראשית לבניין לא נסגרת או ללא מנגנון נעילה** — דלת כניסה ראשית לבניין לא נסגרת אוטומטית, מנגנון נעילה אלקטרוני (אינטרקום) לא פועל, או ציר שבור.. המלצה: תיקון או החלפת סוגר דלת, תיקון מנגנון נעילה אלקטרומגנטי, וכיוון צירים. עלות משוערת: ₪500-₪2000 (ליחידה)', 'דלת כניסה ראשית חייבת להיסגר אוטומטית ולכלול מנגנון נעילה תקין לאבטחת הדיירים', 'דלת כניסה ראשית חייבת להיסגר אוטומטית ולכלול מנגנון נעילה תקין לאבטחת הדיירים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'לובי ורכוש משותף', '**חדר חשמל ראשי ללא סימון או נעילה** — חדר חשמל ראשי ללא שלט אזהרה, ללא נעילה, או עם גישה חופשית לכל דייר. סכנת התחשמלות ושריפה.. המלצה: התקנת מנעול בטיחות, שילוט אזהרה (סכנת חשמל, אסור להיכנס), ווידוא נגישות לחברת החשמל. עלות משוערת: ₪300-₪800 (ליחידה)', '**חדר חשמל ראשי ללא סימון או נעילה** — חדר חשמל ראשי ללא שלט אזהרה, ללא נעילה, או עם גישה חופשית לכל דייר. סכנת התחשמלות ושריפה.. המלצה: התקנת מנעול בטיחות, שילוט אזהרה (סכנת חשמל, אסור להיכנס), ווידוא נגישות לחברת החשמל. עלות משוערת: ₪300-₪800 (ליחידה)', 'חדר חשמל ראשי חייב להיות נעול, מסומן בשלטי אזהרה, ונגיש רק לאנשי מקצוע מורשים', 'חדר חשמל ראשי חייב להיות נעול, מסומן בשלטי אזהרה, ונגיש רק לאנשי מקצוע מורשים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'לובי ורכוש משותף', '**חדר אשפה ללא אוורור או ניקוז** — חדר אשפה משותף ללא מערכת אוורור, ללא ניקוז רצפה, או עם דלת לא אטומה. גורם למפגעי ריח, תברואה, ומזיקים.. המלצה: התקנת מאוורר יניקה, תיקון ניקוז רצפה, אטימת דלת, וריצוף עמיד לשטיפה. עלות משוערת: ₪1500-₪4000 (ליחידה)', '**חדר אשפה ללא אוורור או ניקוז** — חדר אשפה משותף ללא מערכת אוורור, ללא ניקוז רצפה, או עם דלת לא אטומה. גורם למפגעי ריח, תברואה, ומזיקים.. המלצה: התקנת מאוורר יניקה, תיקון ניקוז רצפה, אטימת דלת, וריצוף עמיד לשטיפה. עלות משוערת: ₪1500-₪4000 (ליחידה)', 'חדר אשפה בבניין מגורים חייב לכלול אוורור מכני או טבעי, ניקוז רצפה, וריצוף ניתן לשטיפה', 'חדר אשפה בבניין מגורים חייב לכלול אוורור מכני או טבעי, ניקוז רצפה, וריצוף ניתן לשטיפה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'לובי ורכוש משותף', '**תאורה לקויה בחניון** — תאורה חלשה, נורות שרופות, או אזורים חשוכים בחניון. תאורה לקויה מגבירה סכנת תאונות ופלילות.. המלצה: החלפת נורות שרופות, התקנת גופי תאורת LED, הוספת נקודות תאורה באזורים חשוכים. עלות משוערת: ₪200-₪600 (ליחידה)', '**תאורה לקויה בחניון** — תאורה חלשה, נורות שרופות, או אזורים חשוכים בחניון. תאורה לקויה מגבירה סכנת תאונות ופלילות.. המלצה: החלפת נורות שרופות, התקנת גופי תאורת LED, הוספת נקודות תאורה באזורים חשוכים. עלות משוערת: ₪200-₪600 (ליחידה)', 'חניון חייב בתאורה אחידה בעוצמה מינימלית של 50 לוקס באזורי נסיעה ו-20 לוקס באזורי חנייה', 'חניון חייב בתאורה אחידה בעוצמה מינימלית של 50 לוקס באזורי נסיעה ו-20 לוקס באזורי חנייה', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'לובי ורכוש משותף', '**אינטרקום כניסה לא פועל** — מערכת אינטרקום בכניסה לבניין לא פועלת, מסך שבור, או שכפתורי החיוג לדירות לא מגיבים.. המלצה: תיקון או החלפת מערכת אינטרקום, בדיקת חיווט, החלפת פנל חיצוני פגום. עלות משוערת: ₪800-₪3000 (ליחידה)', '**אינטרקום כניסה לא פועל** — מערכת אינטרקום בכניסה לבניין לא פועלת, מסך שבור, או שכפתורי החיוג לדירות לא מגיבים.. המלצה: תיקון או החלפת מערכת אינטרקום, בדיקת חיווט, החלפת פנל חיצוני פגום. עלות משוערת: ₪800-₪3000 (ליחידה)', 'מערכת אינטרקום חייבת לאפשר תקשורת בין המבקר בכניסה לדיירים ופתיחת דלת מרחוק', 'מערכת אינטרקום חייבת לאפשר תקשורת בין המבקר בכניסה לדיירים ופתיחת דלת מרחוק', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'לובי ורכוש משותף', '**שאריות בנייה / ניקיון לקוי** — שאריות מלט, צבע, דבק או אבק בנייה על ריצוף, חלונות או כלים סניטריים.. המלצה: ניקיון בנייה מקצועי. עלות משוערת: ₪1500-₪3500 (ליחידה)', '**שאריות בנייה / ניקיון לקוי** — שאריות מלט, צבע, דבק או אבק בנייה על ריצוף, חלונות או כלים סניטריים.. המלצה: ניקיון בנייה מקצועי. עלות משוערת: ₪1500-₪3500 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'לובי ורכוש משותף', '**כתמי מלט על ריצוף** — כתמי מלט או דבק אריחים שנשארו על הריצוף לאחר העבודה.. המלצה: ניקוי מקצועי בחומרים ייעודיים. עלות משוערת: ₪200-₪600 (ליחידה)', '**כתמי מלט על ריצוף** — כתמי מלט או דבק אריחים שנשארו על הריצוף לאחר העבודה.. המלצה: ניקוי מקצועי בחומרים ייעודיים. עלות משוערת: ₪200-₪600 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'לובי ורכוש משותף', '**מעקה לא יציב / גובה לא תקני** — מעקה מרפסת או מדרגות שלא יציב, או שגובהו נמוך מהנדרש (105 ס"מ).. המלצה: הגבהת / חיזוק / החלפת מעקה. עלות משוערת: ₪300-₪1500 (למ"א)', '**מעקה לא יציב / גובה לא תקני** — מעקה מרפסת או מדרגות שלא יציב, או שגובהו נמוך מהנדרש (105 ס"מ).. המלצה: הגבהת / חיזוק / החלפת מעקה. עלות משוערת: ₪300-₪1500 (למ"א)', 'ת"י 1142 — גובה מעקה מינימלי: 105 ס"מ. מרווח בין פסים: עד 10 ס"מ', 'ת"י 1142 — גובה מעקה מינימלי: 105 ס"מ. מרווח בין פסים: עד 10 ס"מ', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'לובי ורכוש משותף', '**חניה — סימון לקוי או חסר** — סימון חניה חסר, לא ברור, או לא תואם לתוכנית.. המלצה: סימון חניות מחדש בהתאם לתוכנית. עלות משוערת: ₪200-₪500 (ליחידה)', '**חניה — סימון לקוי או חסר** — סימון חניה חסר, לא ברור, או לא תואם לתוכנית.. המלצה: סימון חניות מחדש בהתאם לתוכנית. עלות משוערת: ₪200-₪500 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'נגישות', '**רמפת נגישות חסרה או בשיפוע לא תקני** — רמפה לנכים בכניסה לבניין חסרה, שיפועה חד מדי (מעל 8%), ללא מעקה בטיחות, או בלי משטח אופקי בראשה.. המלצה: בניית רמפת נגישות תקנית או תיקון שיפוע, התקנת מעקות, והוספת משטח אופקי. עלות משוערת: ₪3000-₪12000 (ליחידה)', '**רמפת נגישות חסרה או בשיפוע לא תקני** — רמפה לנכים בכניסה לבניין חסרה, שיפועה חד מדי (מעל 8%), ללא מעקה בטיחות, או בלי משטח אופקי בראשה.. המלצה: בניית רמפת נגישות תקנית או תיקון שיפוע, התקנת מעקות, והוספת משטח אופקי. עלות משוערת: ₪3000-₪12000 (ליחידה)', 'ת"י 1918 חלק 1 — רמפת נגישות חייבת להיות בשיפוע מקסימלי של 8% (1:12), רוחב מינימלי 130 ס"מ, עם מעקות משני צדדים ומשטח אופקי בראש ובתחתית', 'ת"י 1918 חלק 1 — רמפת נגישות חייבת להיות בשיפוע מקסימלי של 8% (1:12), רוחב מינימלי 130 ס"מ, עם מעקות משני צדדים ומשטח אופקי בראש ובתחתית', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'נגישות', '**מעלית ללא נגישות לנכים** — מעלית ללא כפתורים בגובה נגיש, ללא כיתוב ברייל, ללא הכרזה קולית על קומות, או פתח צר מדי לכיסא גלגלים.. המלצה: שדרוג לוח כפתורים עם ברייל, התקנת מערכת הכרזה קולית, בדיקת רוחב פתח. עלות משוערת: ₪2000-₪8000 (ליחידה)', '**מעלית ללא נגישות לנכים** — מעלית ללא כפתורים בגובה נגיש, ללא כיתוב ברייל, ללא הכרזה קולית על קומות, או פתח צר מדי לכיסא גלגלים.. המלצה: שדרוג לוח כפתורים עם ברייל, התקנת מערכת הכרזה קולית, בדיקת רוחב פתח. עלות משוערת: ₪2000-₪8000 (ליחידה)', 'ת"י 1918 חלק 3 — מעלית נגישה חייבת לכלול: כפתורים בגובה נגיש, סימון ברייל, הכרזה קולית, רוחב פתח 90 ס"מ לפחות, ומראה אחורית', 'ת"י 1918 חלק 3 — מעלית נגישה חייבת לכלול: כפתורים בגובה נגיש, סימון ברייל, הכרזה קולית, רוחב פתח 90 ס"מ לפחות, ומראה אחורית', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'נגישות', '**חניית נכים חסרה או לא מסומנת** — חניית נכים לא מסומנת, ללא שילוט, ברוחב לא מספק, או ללא מעבר נגיש ממנה לכניסת הבניין.. המלצה: סימון וצביעת חניית נכים, התקנת שילוט, הרחבה לרוחב תקני, והתקנת מעבר נגיש. עלות משוערת: ₪1000-₪3000 (ליחידה)', '**חניית נכים חסרה או לא מסומנת** — חניית נכים לא מסומנת, ללא שילוט, ברוחב לא מספק, או ללא מעבר נגיש ממנה לכניסת הבניין.. המלצה: סימון וצביעת חניית נכים, התקנת שילוט, הרחבה לרוחב תקני, והתקנת מעבר נגיש. עלות משוערת: ₪1000-₪3000 (ליחידה)', 'ת"י 1918 חלק 1 — נדרשת לפחות חנייה נגישה אחת לכל 25 חניות, ברוחב 3.5 מטר, עם סימון ושילוט בולטים ומעבר נגיש', 'ת"י 1918 חלק 1 — נדרשת לפחות חנייה נגישה אחת לכל 25 חניות, ברוחב 3.5 מטר, עם סימון ושילוט בולטים ומעבר נגיש', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'נגישות', '**העדר מאחז יד בחדר מדרגות** — מאחז יד (handrail) חסר בצד אחד או בשני צדדי חדר המדרגות, לא רציף, או בגובה לא תקני.. המלצה: התקנת מאחז יד נירוסטה רציף בשני צדדי חדר המדרגות, בגובה תקני עם חזרה לקיר. עלות משוערת: ₪200-₪450 (למ"א)', '**העדר מאחז יד בחדר מדרגות** — מאחז יד (handrail) חסר בצד אחד או בשני צדדי חדר המדרגות, לא רציף, או בגובה לא תקני.. המלצה: התקנת מאחז יד נירוסטה רציף בשני צדדי חדר המדרגות, בגובה תקני עם חזרה לקיר. עלות משוערת: ₪200-₪450 (למ"א)', 'ת"י 1918 חלק 1 — נדרש מאחז יד רציף בשני צדדי חדר המדרגות, בגובה 85-100 ס"מ, עם חזרה לקיר בקצוות', 'ת"י 1918 חלק 1 — נדרש מאחז יד רציף בשני צדדי חדר המדרגות, בגובה 85-100 ס"מ, עם חזרה לקיר בקצוות', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'נגישות', '**מעבר מעלית צר מדי לכיסא גלגלים** — המרווח בין דלת המעלית לקיר הנגדי בקומה קטן מדי, מונע כניסה ויציאה נוחה של כיסא גלגלים.. המלצה: הסרת חסימות, הרחבת מרווח תמרון מול דלת המעלית, במקרים קיצוניים — שינוי תכנוני. עלות משוערת: ₪500-₪5000 (ליחידה)', '**מעבר מעלית צר מדי לכיסא גלגלים** — המרווח בין דלת המעלית לקיר הנגדי בקומה קטן מדי, מונע כניסה ויציאה נוחה של כיסא גלגלים.. המלצה: הסרת חסימות, הרחבת מרווח תמרון מול דלת המעלית, במקרים קיצוניים — שינוי תכנוני. עלות משוערת: ₪500-₪5000 (ליחידה)', 'ת"י 1918 חלק 3 — מרווח מינימלי של 150 ס"מ נדרש מול דלת המעלית לתמרון כיסא גלגלים', 'ת"י 1918 חלק 3 — מרווח מינימלי של 150 ס"מ נדרש מול דלת המעלית לתמרון כיסא גלגלים', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'נגישות', '**סף מפתן גבוה בכניסה לבניין** — מפתן (סף) גבוה בכניסה לבניין המונע מעבר כיסא גלגלים או עגלת תינוק. הפרש גובה מעל 2 ס"מ ללא רמפה.. המלצה: התקנת רמפון (ramp insert) או הורדת מפתן לגובה תקני, ביצוע מעבר חלק ללא הפרשי גובה. עלות משוערת: ₪500-₪2000 (ליחידה)', '**סף מפתן גבוה בכניסה לבניין** — מפתן (סף) גבוה בכניסה לבניין המונע מעבר כיסא גלגלים או עגלת תינוק. הפרש גובה מעל 2 ס"מ ללא רמפה.. המלצה: התקנת רמפון (ramp insert) או הורדת מפתן לגובה תקני, ביצוע מעבר חלק ללא הפרשי גובה. עלות משוערת: ₪500-₪2000 (ליחידה)', 'ת"י 1918 חלק 1 — הפרש גובה מקסימלי בכניסה נגישה הוא 2 ס"מ, מעל לכך נדרשת רמפה או הורדת מפלס', 'ת"י 1918 חלק 1 — הפרש גובה מקסימלי בכניסה נגישה הוא 2 ס"מ, מעל לכך נדרשת רמפה או הורדת מפלס', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'נגרות ודלתות פנים', '**דלת לא נסגרת כראוי** — דלת פנים שלא נסגרת כראוי — שפשוף ברצפה, משקוף עקום, או ציר רופף.. המלצה: כוונון צירים, שיוף תחתית דלת, או החלפת דלת. עלות משוערת: ₪150-₪400 (ליחידה)', '**דלת לא נסגרת כראוי** — דלת פנים שלא נסגרת כראוי — שפשוף ברצפה, משקוף עקום, או ציר רופף.. המלצה: כוונון צירים, שיוף תחתית דלת, או החלפת דלת. עלות משוערת: ₪150-₪400 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'נגרות ודלתות פנים', '**מנעול תקוע / לא נועל** — מנעול דלת שלא פועל כראוי — תקוע, קשה לסיבוב, או לא נועל.. המלצה: שימון, כוונון או החלפת מנעול. עלות משוערת: ₪150-₪450 (ליחידה)', '**מנעול תקוע / לא נועל** — מנעול דלת שלא פועל כראוי — תקוע, קשה לסיבוב, או לא נועל.. המלצה: שימון, כוונון או החלפת מנעול. עלות משוערת: ₪150-₪450 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'נגרות ודלתות פנים', '**משקוף פגום / לא ישר** — משקוף דלת שעקום, פגום או לא מותקן ישר.. המלצה: יישור או החלפת משקוף. עלות משוערת: ₪300-₪800 (ליחידה)', '**משקוף פגום / לא ישר** — משקוף דלת שעקום, פגום או לא מותקן ישר.. המלצה: יישור או החלפת משקוף. עלות משוערת: ₪300-₪800 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'נגרות ודלתות פנים', '**ארון מטבח — דלת לא מיושרת** — דלת ארון מטבח שלא מיושרת — לא נסגרת כראוי או לא במפלס עם שאר הדלתות.. המלצה: כוונון צירים, יישור דלת. עלות משוערת: ₪100-₪300 (ליחידה)', '**ארון מטבח — דלת לא מיושרת** — דלת ארון מטבח שלא מיושרת — לא נסגרת כראוי או לא במפלס עם שאר הדלתות.. המלצה: כוונון צירים, יישור דלת. עלות משוערת: ₪100-₪300 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'נגרות ודלתות פנים', '**דלת כניסה — אטימה לקויה** — דלת כניסה ראשית שלא אוטמת כראוי — חדירת אוויר, אור או מים.. המלצה: החלפת אטמים, כוונון דלת, תיקון מסגרת. עלות משוערת: ₪200-₪600 (ליחידה)', '**דלת כניסה — אטימה לקויה** — דלת כניסה ראשית שלא אוטמת כראוי — חדירת אוויר, אור או מים.. המלצה: החלפת אטמים, כוונון דלת, תיקון מסגרת. עלות משוערת: ₪200-₪600 (ליחידה)', 'ת"י 23 — דלת כניסה חייבת לאטום כנגד חדירת מים ואוויר', 'ת"י 23 — דלת כניסה חייבת לאטום כנגד חדירת מים ואוויר', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'צביעה', '**פילינג / התקלפות צבע** — צבע שמתקלף מהקיר או התקרה. עלול לנבוע מרטיבות, הכנה לקויה או צבע לא מתאים.. המלצה: גירוד צבע ישן, הכנת משטח, צביעה ב-2 שכבות. עלות משוערת: ₪200-₪800 (ליחידה)', '**פילינג / התקלפות צבע** — צבע שמתקלף מהקיר או התקרה. עלול לנבוע מרטיבות, הכנה לקויה או צבע לא מתאים.. המלצה: גירוד צבע ישן, הכנת משטח, צביעה ב-2 שכבות. עלות משוערת: ₪200-₪800 (ליחידה)', 'ת"י 1515 חלק 3 — צבע חייב להיות צמוד ואחיד — התקלפות מהווה ליקוי', 'ת"י 1515 חלק 3 — צבע חייב להיות צמוד ואחיד — התקלפות מהווה ליקוי', true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'צביעה', '**כתמים / אי-אחידות בצבע** — כתמי צבע, הבדלי גוון, או חוסר אחידות במשטח הצבוע.. המלצה: צביעה מחדש של המשטח הפגום ב-2 שכבות. עלות משוערת: ₪150-₪500 (ליחידה)', '**כתמים / אי-אחידות בצבע** — כתמי צבע, הבדלי גוון, או חוסר אחידות במשטח הצבוע.. המלצה: צביעה מחדש של המשטח הפגום ב-2 שכבות. עלות משוערת: ₪150-₪500 (ליחידה)', 'ת"י 1515 חלק 3 — צביעה חייבת להיות אחידה בגוון ובמרקם', 'ת"י 1515 חלק 3 — צביעה חייבת להיות אחידה בגוון ובמרקם', true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'צביעה', '**טפטופי צבע / שפכים** — טפטופי צבע נראים לעין על קירות, תקרות, או על אלמנטים סמוכים (חלונות, דלתות, ריצוף).. המלצה: ניקוי טפטופים ותיקון מקומי. עלות משוערת: ₪100-₪300 (ליחידה)', '**טפטופי צבע / שפכים** — טפטופי צבע נראים לעין על קירות, תקרות, או על אלמנטים סמוכים (חלונות, דלתות, ריצוף).. המלצה: ניקוי טפטופים ותיקון מקומי. עלות משוערת: ₪100-₪300 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מיזוג אוויר', '**מזגן לא מקרר / לא מחמם** — יחידת מיזוג אוויר שלא מגיעה לטמפרטורה הנדרשת.. המלצה: בדיקת גז, ניקוי מסננים, תיקון או החלפת יחידה. עלות משוערת: ₪200-₪600 (ליחידה)', '**מזגן לא מקרר / לא מחמם** — יחידת מיזוג אוויר שלא מגיעה לטמפרטורה הנדרשת.. המלצה: בדיקת גז, ניקוי מסננים, תיקון או החלפת יחידה. עלות משוערת: ₪200-₪600 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מיזוג אוויר', '**רעש חריג מיחידת מיזוג** — רעש חריג מיחידה פנימית או חיצונית של המזגן.. המלצה: בדיקת חיבורים, איזון מאוורר, תיקון. עלות משוערת: ₪150-₪500 (ליחידה)', '**רעש חריג מיחידת מיזוג** — רעש חריג מיחידה פנימית או חיצונית של המזגן.. המלצה: בדיקת חיבורים, איזון מאוורר, תיקון. עלות משוערת: ₪150-₪500 (ליחידה)', NULL, NULL, true, 'low');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'מיזוג אוויר', '**נזילת קונדנס ממזגן** — נזילת מים (קונדנסציה) מיחידת המזגן הפנימית.. המלצה: בדיקת צנרת ניקוז קונדנס, ניקוי או תיקון. עלות משוערת: ₪150-₪400 (ליחידה)', '**נזילת קונדנס ממזגן** — נזילת מים (קונדנסציה) מיחידת המזגן הפנימית.. המלצה: בדיקת צנרת ניקוז קונדנס, ניקוי או תיקון. עלות משוערת: ₪150-₪400 (ליחידה)', NULL, NULL, true, 'medium');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'גז', '**צנרת גז – נזילה או התקנה לקויה** — נזילת גז מצנרת הגז הפנימית בדירה, חיבורים לא אטומים, או צנרת שאינה עומדת בדרישות התקן.. המלצה: לזמן טכנאי גז מוסמך לתיקון מיידי. אין לבצע תיקונים עצמאיים בצנרת גז. לבצע בדיקת אטימות לאחר התיקון.. עלות משוערת: ₪300-₪1500 (ליחידה)', '**צנרת גז – נזילה או התקנה לקויה** — נזילת גז מצנרת הגז הפנימית בדירה, חיבורים לא אטומים, או צנרת שאינה עומדת בדרישות התקן.. המלצה: לזמן טכנאי גז מוסמך לתיקון מיידי. אין לבצע תיקונים עצמאיים בצנרת גז. לבצע בדיקת אטימות לאחר התיקון.. עלות משוערת: ₪300-₪1500 (ליחידה)', 'ת"י 158 — מערכת גז פנימית חייבת לעמוד בבדיקת אטימות בלחץ של 60 מיליבר למשך 15 דקות ללא ירידת לחץ.', 'ת"י 158 — מערכת גז פנימית חייבת לעמוד בבדיקת אטימות בלחץ של 60 מיליבר למשך 15 דקות ללא ירידת לחץ.', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'גז', '**ברז גז – חסר או לא תקין** — ברז ניתוק גז חסר לפני מכשיר צורך גז (תנור, קומקום גז), או שברז קיים אינו סוגר כראוי.. המלצה: להתקין ברז גז תקני לפני כל מכשיר צורך גז, באמצעות טכנאי גז מוסמך.. עלות משוערת: ₪200-₪500 (ליחידה)', '**ברז גז – חסר או לא תקין** — ברז ניתוק גז חסר לפני מכשיר צורך גז (תנור, קומקום גז), או שברז קיים אינו סוגר כראוי.. המלצה: להתקין ברז גז תקני לפני כל מכשיר צורך גז, באמצעות טכנאי גז מוסמך.. עלות משוערת: ₪200-₪500 (ליחידה)', 'ת"י 158 — יש להתקין ברז ניתוק נפרד לפני כל מכשיר צורך גז, מסוג שסתום כדורי מאושר.', 'ת"י 158 — יש להתקין ברז ניתוק נפרד לפני כל מכשיר צורך גז, מסוג שסתום כדורי מאושר.', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'גז', '**גז — נזילה או ריח** — חשד לנזילת גז — ריח גז או תוצאת בדיקת לחץ לא תקינה.. המלצה: סגירת ברז ראשי, קריאה לטכנאי גז מוסמך מיידית. עלות משוערת: ₪300-₪800 (ליחידה)', '**גז — נזילה או ריח** — חשד לנזילת גז — ריח גז או תוצאת בדיקת לחץ לא תקינה.. המלצה: סגירת ברז ראשי, קריאה לטכנאי גז מוסמך מיידית. עלות משוערת: ₪300-₪800 (ליחידה)', 'תקנות הגז — מערכת גז חייבת להיות אטומה לחלוטין — בדיקת לחץ חובה', 'תקנות הגז — מערכת גז חייבת להיות אטומה לחלוטין — בדיקת לחץ חובה', true, 'critical');
INSERT INTO defect_library (organization_id, user_id, source, category, title, description, standard, standard_reference, is_global, default_severity) VALUES (NULL, NULL, 'system', 'גז', '**צנרת גז חשופה / לא מוגנת** — צנרת גז שחשופה או לא מוגנת בהתאם לתקנות.. המלצה: הגנה על צנרת בהתאם לתקנות. עלות משוערת: ₪200-₪600 (ליחידה)', '**צנרת גז חשופה / לא מוגנת** — צנרת גז שחשופה או לא מוגנת בהתאם לתקנות.. המלצה: הגנה על צנרת בהתאם לתקנות. עלות משוערת: ₪200-₪600 (ליחידה)', 'תקנות הגז — צנרת גז חייבת להיות מוגנת ומסומנת', 'תקנות הגז — צנרת גז חייבת להיות מוגנת ומסומנת', true, 'medium');
